-- Chien -> humain, Fête, Volume 9

insert into public.message_templates (user_id,title,content,tone,is_system,is_manual_only,occasion,animal_type,animal_direction) values

(null,'Joyeuse fête. J''ai observé ta façon de sourire en entendant une conversation que tu n''étais pas censé entendre.',$$Joyeuse fête. J''ai observé ta façon de sourire en entendant une conversation que tu n''étais pas censé entendre.
Tu avais le dos tourné. Tu faisais autre chose. Et quelque chose d''une conversation proche t''a atteint. Et j''ai vu ce sourire involontaire. Celui qui dit que tu as entendu quelque chose de drôle ou de touchant même si tu n''étais pas censé écouter. Joyeuse fête, mon humain préféré.
Avec observation de ton sourire involontaire d''écoute accidentelle, — {prenom}, ton animal dont les oreilles sont aussi attentives que les miennes 👂$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai observé comment tu changes de rythme quand la soirée approche de la fin.',$$Joyeuse fête. J''ai observé comment tu changes de rythme quand la soirée approche de la fin.
Progressivement tu ralentis. Les propositions s''espacent. Les conversations deviennent plus intimes. Moins de monde à la fois. Plus de profondeur par groupe. Cette façon de laisser la soirée se concentrer naturellement vers sa fin. Joyeuse fête, mon humain préféré.
Avec observation de ta décélération progressive et de sa naturalité, — {prenom}, ton animal admirateur de tes fins de soirée organiques 🌙$$,'touching',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. Je comprends pas pourquoi les gens nettoient avant que les invités arrivent alors qu''ils vont salir.',$$Joyeuse fête. Je comprends pas pourquoi les gens nettoient avant que les invités arrivent alors qu''ils vont salir.
Tu as passé du temps à nettoyer avant que les gens arrivent. Puis les gens sont arrivés. Et ce soir tu vas nettoyer à nouveau. Peut-être que le nettoyage d''avant c''est pour toi. Pour ta tranquillité. Pas pour les invités. Joyeuse fête, mon humain préféré.
Avec théorie du nettoyage pré-fête comme acte pour soi plutôt que pour les autres, — {prenom}, ton animal philosophe de tes rituels de préparation 🧹$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai mémorisé l''odeur de l''appartement avant que les invités arrivent.',$$Joyeuse fête. J''ai mémorisé l''odeur de l''appartement avant que les invités arrivent.
Cette odeur-là. L''appartement propre. Avec les premières odeurs de cuisine. Et quelque chose de l''anticipation. De l''excitation douce d''avant. Cette version de l''appartement qui n''existe que quelques minutes avant que tout commence. Joyeuse fête, mon humain préféré.
Avec mémorisation de l''odeur rare des quelques minutes avant que tout commence, — {prenom}, ton animal archiviste des moments d''avant 👃$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai observé ta façon de vérifier le frigo plusieurs fois ce soir.',$$Joyeuse fête. J''ai observé ta façon de vérifier le frigo plusieurs fois ce soir.
Avant que les invités arrivent. Puis après les premières arrivées. Puis avant le repas. Ces vérifications du frigo comme vérifications de l''état de la soirée. Comme si voir que tout y était signifiait que tout allait bien. Joyeuse fête, mon humain préféré.
Avec observation de tes vérifications du frigo comme métaphore de ton état de soirée, — {prenom}, ton animal lecteur de tes anxiétés douces 🧊$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai observé comment tu gardes ta bonne humeur face aux imprévus.',$$Joyeuse fête. J''ai observé comment tu gardes ta bonne humeur face aux imprévus.
Il y en a eu deux ce soir. Deux petites choses qui n''ont pas marché comme prévu. Et chaque fois tu as ajusté. Sans que ça se voie sur ton visage pendant plus de quelques secondes. Joyeuse fête, mon humain préféré.
Avec admiration pour ton absorption des imprévus en quelques secondes invisibles, — {prenom}, ton animal témoin de ta résilience de soirée 🔧$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. Je comprends pas pourquoi les gens font la queue pour les toilettes alors qu''on pourrait s''organiser.',$$Joyeuse fête. Je comprends pas pourquoi les gens font la queue pour les toilettes alors qu''on pourrait s''organiser.
Ce soir il y a eu un moment. Plusieurs personnes avaient besoin des toilettes en même temps. Et une file informelle s''est formée. La politesse comme infrastructure. Joyeuse fête, mon humain préféré.
Avec fascination pour la file invisible des toilettes et la politesse comme infrastructure sociale, — {prenom}, ton animal qui ne fait jamais la queue 🚪$$,'touching',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai étudié ta façon de plier un torchon proprement.',$$Joyeuse fête. J''ai étudié ta façon de plier un torchon proprement.
En tiers. Puis en tiers encore. Avec les bords alignés. Posé sur le comptoir. Ce geste automatique. Ce soin pour un objet utilitaire. Joyeuse fête, mon humain préféré.
Avec observation de ton soin pour les objets utilitaires et ce qu''il dit sur toi, — {prenom}, ton animal attentif à tes soins pour le quotidien 🧺$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai observé ta façon d''écouter la musique différemment ce soir.',$$Joyeuse fête. J''ai observé ta façon d''écouter la musique différemment ce soir.
Elle est là en fond. Et puis parfois un morceau arrive et quelque chose dans ton visage change légèrement. Tu es là et en même temps ailleurs une seconde. Dans un souvenir ou une émotion. Puis tu reviens. Joyeuse fête, mon humain préféré.
Avec observation de tes micro-voyages musicaux au milieu de la conversation, — {prenom}, ton animal gardien de tes absences musicales 🎵$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai observé comment tu réagis quand quelqu''un complimente ton appartement.',$$Joyeuse fête. J''ai observé comment tu réagis quand quelqu''un complimente ton appartement.
Tu regardes l''appartement un instant. Comme si tu le voyais par leurs yeux. Avec une légère surprise. Puis tu remercies. Simplement. Joyeuse fête, mon humain préféré.
Avec observation de ton regard nouveau sur ton appartement par les yeux des autres, — {prenom}, ton animal qui te voit voir ton espace différemment 🏠$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. Je comprends pas pourquoi les gens choisissent toujours le même endroit pour s''asseoir.',$$Joyeuse fête. Je comprends pas pourquoi les gens choisissent toujours le même endroit pour s''asseoir.
Ce soir plusieurs personnes sont revenues au même siège après s''être levées. Cette territorialité douce et non déclarée. Moi je comprends ça très bien. Certains endroits nous choisissent autant qu''on les choisit. Joyeuse fête, mon humain préféré.
Avec compréhension de la territorialité douce des fêtes et solidarité de ma propre pratique, — {prenom}, ton animal expert en territoires choisis 🪑$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai mémorisé ta façon de gérer plusieurs choses en cuisine en même temps.',$$Joyeuse fête. J''ai mémorisé ta façon de gérer plusieurs choses en cuisine en même temps.
Le four. La casserole. Le four de nouveau. La vérification. Cette danse entre plusieurs cuissons. Cette façon de tenir plusieurs fils en même temps sans en perdre aucun. C''est de l''orchestration. Joyeuse fête, mon humain préféré.
Avec admiration pour ton orchestration culinaire multi-tâches sans fausse note, — {prenom}, ton animal spectateur de ta symphonie de cuisine 🎼$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai observé comment tu te sens différent dans ta propre maison ce soir.',$$Joyeuse fête. J''ai observé comment tu te sens différent dans ta propre maison ce soir.
Tu occupes l''espace différemment. Tu te déplaces avec plus d''intention. Tu es chez toi mais tu es aussi hôte. Ces deux états en même temps. Cette façon d''habiter ton espace en étant à la fois dedans et en train de le regarder de l''extérieur. Joyeuse fête, mon humain préféré.
Avec observation de ton double état d''habitant et d''hôte simultané dans ton espace, — {prenom}, ton animal témoin de ta dualité de soirée 🏠$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai observé comment tu réagis quand quelqu''un propose d''aider sans qu''on lui demande.',$$Joyeuse fête. J''ai observé comment tu réagis quand quelqu''un propose d''aider sans qu''on lui demande.
Tu acceptes avec gratitude. Sans faire semblant que tu n''as pas besoin. Tu laisses l''aide être une aide. Et tu intègres cette aide dans ton flux sans en faire un événement. Joyeuse fête, mon humain préféré.
Avec admiration pour ta façon de recevoir l''aide sans la refuser ni la surestimer, — {prenom}, ton animal témoin de ta grâce à recevoir 🤝$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. Je comprends pas pourquoi les gens disent que la soirée passe vite alors qu''ils vérifient l''heure.',$$Joyeuse fête. Je comprends pas pourquoi les gens disent que la soirée passe vite alors qu''ils vérifient l''heure.
Ça passe tellement vite. Puis un regard vers l''heure. Peut-être que dire que ça passe vite c''est une façon de le regretter. Joyeuse fête, mon humain préféré.
Avec théorie du vite comme regret déguisé et logique bien établie, — {prenom}, ton animal philosophe du temps festif 🕰️$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai étudié ta façon de choisir où mettre les fleurs reçues.',$$Joyeuse fête. J''ai étudié ta façon de choisir où mettre les fleurs reçues.
Tu les tiens. Tu regardes la pièce. Tu essaies mentalement plusieurs endroits. Puis tu choisis. Cette façon de trouver la place de ce qui vient d''arriver dans ce qui existait déjà. Joyeuse fête, mon humain préféré.
Avec observation de ton processus de placement des fleurs et sa logique d''intégration, — {prenom}, ton animal expert en placement des nouveautés dans l''existant 🌺$$,'touching',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai observé ta façon de dire quelque chose de gentil à chaque invité qui part.',$$Joyeuse fête. J''ai observé ta façon de dire quelque chose de gentil à chaque invité qui part.
Pas le même quelque chose. Quelque chose de personnalisé. Un mot sur quelque chose qu''il a dit. Sur quelque chose qu''il a fait. Ces petits mots de départ personnalisés qui disent que tu as vu cette personne ce soir. Joyeuse fête, mon humain préféré.
Avec admiration pour tes mots de départ personnalisés et leur soin de l''individu, — {prenom}, ton animal admirateur de ta mémoire affective des soirées 🌟$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai observé comment tu te retrouves seul une minute et ce que tu fais.',$$Joyeuse fête. J''ai observé comment tu te retrouves seul une minute et ce que tu fais.
Tu regardes. Tu fais le tour des yeux. Tu souffles légèrement. Tu prends quelque chose à manger ou à boire. Et tu repars. Ces minutes seules dans ta propre fête. Ces parenthèses de toi. Joyeuse fête, mon humain préféré.
Avec observation de tes parenthèses solitaires au milieu de tout le monde et leur nécessité, — {prenom}, ton animal pour qui ces minutes-là sont les plus précieuses 🌿$$,'touching',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. Je comprends pas pourquoi les gens disent on refait ça bientôt sans jamais fixer de date.',$$Joyeuse fête. Je comprends pas pourquoi les gens disent on refait ça bientôt sans jamais fixer de date.
À chaque départ ce soir on refait ça bientôt. C''est une intention sincère. Pas un mensonge. Une aspiration. Peut-être que fixer une date c''est trop engageant. Et que l''intention suffit pour l''instant. Joyeuse fête, mon humain préféré.
Avec compréhension du bientôt comme intention sincère plutôt que promesse datée, — {prenom}, ton animal en paix avec les futurs indéfinis 📅$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai mémorisé la façon dont le silence s''installait progressivement après les départs.',$$Joyeuse fête. J''ai mémorisé la façon dont le silence s''installait progressivement après les départs.
D''abord quelques voix en moins. Puis l''appartement plus grand. Puis les bruits qui reprennent leur place normale. Le frigo. La ville dehors. Et toi. Et moi. Cette installation progressive du silence. Ce retour à nous deux. Joyeuse fête, mon humain préféré.
Avec mémorisation de chaque étape du retour au silence et sa beauté progressive, — {prenom}, ton animal pour le silence d''après qui vaut tout le bruit d''avant ❤️$$,'touching',true,false,'nameday','chien','from')

on conflict do nothing;
